var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"소꿉 장난이나 하려는 줄 알았는데. 제법 진심인가 봐?","JPN":"おままごとでもしようとしてるのかと思ったんだが。結構本気みたいだな？","ENG":"I thought you just wanted to play pretend, but it seems like you’re serious about it.","TWN":"我還以為你是鬧著玩的，結果竟然是認真的喔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"네가 오면 꼭 해주고 싶던 말이 있었어. 귀 좀 가까이 대 봐.","JPN":"汝が来たら必ずしてやろうと思った話があるんだ。ちょっと耳を貸せ。","ENG":"There’s something I wanted to tell you. Lean in a little closer.","TWN":"我有些話一直想跟你說，耳朵靠過來一點。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……대체 이 유치찬란한 장소는 뭐야?! 취향 진짜 특이한 거 알아?","JPN":"……この幼稚な場所は何だ！？　汝の趣味は本当に変わってるな。","ENG":"...What’s with this childish venue?! You have a really weird taste for things.","TWN":"……這個超幼稚的地方到底是怎麼回事？！你的喜好真的很特別你知道嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"대체 어떤 마녀가 이런 동화처럼 꾸민 장소에서 결혼을 해!","JPN":"一体どんな魔女がこんなおとぎ話のようなところで結婚をするんだ！","ENG":"What kind of a witch would hold a wedding in a place decorated like a fairy tale?!","TWN":"哪個魔女會在這種像童話世界般的地方結婚啦！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"조금 더 으스스하게, 주인 없는 무덤들도 몇 가져다 놓고, 망령들의 환호를 받으면서 해도 모자랄 판에!","JPN":"もう少し薄気味悪く！　無縁墓も何カ所か作って！　亡霊の歓声を浴びながらやっても足りないぞ！","ENG":"It could be so much better, with some unmarked graves and ghosts cheering us on!","TWN":"應該要再陰森一點，起碼弄幾個無名氏墳墓來，再搭配一些鬼叫聲吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"아니면 차라리 우리 카페에서 하던가!","JPN":"そうでなければ、いっそのこと妾のカフェでやれ！","ENG":"Or even my cafe would work as the venue!","TWN":"這樣倒不如在我們咖啡廳裡舉行！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……아. 됐어. 더 말했다간 머리나 아프지.","JPN":"……あ。もういい。これ以上話しても頭痛がするだけだ。","ENG":"...Ugh. Forget it. This isn’t helping anyone.","TWN":"……真是的，算啦！再說下去我會氣死。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"동화 같은 결말을 기대하나 본데, 마녀를 반려로 맞이하는 건 좀 다를 거야.","JPN":"おとぎ話のような結末を期待しているようだが、魔女を伴侶に迎えるというのは少し違うぞ。","ENG":"I can see you’re expecting a fairy-tale-like ending, but having a witch as your partner is going to be different.","TWN":"我看你好像是在期待童話故事般的結局是吧？但當你的另一半是魔女時可不是這麼回事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"마녀의 역할은 주인공이나 괴롭히다가 평생 깰 수 없는 긴 잠에 빠져드는 게 고작이거든.","JPN":"魔女の役割といえば、せいぜい主人公をいじめては一生目覚めない深い眠りにつくぐらいだ。","ENG":"It’s a witch’s role to harass the protagonist and then fall into deep sleep that they can never wake up from.","TWN":"魔女的角色就是專門折磨故事裡的主角，然後一輩子沉睡不起。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그게 싫다는 건 아니야. 보다시피 꽤 아늑한 관을 가지고 있어서.","JPN":"だが、それが嫌だということではない。見てのとおり、居心地の良い棺を持ってるからな。","ENG":"Not that I mind that. As you can see, I have a pretty cozy coffin.","TWN":"我不是討厭的意思，你也看到啦，我有一個蠻舒適的棺材。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……뭐? 잠든 마녀를 깨울 방법?","JPN":"……は？　眠りについた魔女を起こす方法？","ENG":"...What? How to wake a sleeping witch?","TWN":"……什麼？喚醒沉睡魔女的方法？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"이런 질문은 처음이네. 진심으로 궁금해서 묻는 건 아니겠지, 설마?","JPN":"そんな質問は初めてだな。まさか、本当に気になって聞くわけではないだろう？","ENG":"I haven’t heard that one before. You’re not seriously asking that, right?","TWN":"還是第一次有人問這個問題，你根本不是真心想問的吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"잠든 마녀를 깨워 봤자 <color=#ffd34c>함께 오래오래 행복하게 살았습니다</color>는 커녕 살 찌워서 잡아 먹히거나, 악랄한 종신 계약서에 사인해서 평생 부림 당하거나 둘 중 하나라고.","JPN":"眠りについた魔女を起こしても<color=#ffd34c>一緒にいつまでも幸せに暮らしましたとさ</color>はおろか太らされて食われるか、あくどい終身契約書にサインさせられて一生こき使われるかだ。","ENG":"There won’t be a <color=#ffd34c>“they lived happily ever after.”</color>Waking a sleeping witch will only lead to being fattened up and getting eaten, or signing a shady lifetime contract just to be bossed around forever.","TWN":"要是喚醒沉睡的魔女，結局可不是<color=#ffd34c>永遠過著幸福快樂的生活</color>，結局只有二種，一種是把你養肥後再吃掉，一種是讓你在終身契約上簽名一輩子使喚你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"각오가 되어 있다면, 한번 선택해 봐. 어느 쪽이 좋을지.","JPN":"覚悟ができているのなら、一度選択してみろ。どちらがいいか。","ENG":"If you’re willing to take the risk, choose the option you’d prefer.","TWN":"想清楚後再決定，你要選擇哪一個？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};